    cin >> N >> x;

    int bottom = 2 * N - 1;
    deque<int> val;
    bool used[500001] = {false};

    if (x >= 2 && x + 2 <= bottom) {
        val.push_back(x + 1);
        used[x + 1] = true;
        val.push_back(x);
        used[x] = true;
        val.push_back(x - 1);
        used[x - 1] = true;
        val.push_back(x + 2);
        used[x + 2] = true;
    } else if (x - 2 >= 1 && x + 1 <= bottom) {
        val.push_back(x - 1);
        used[x - 1] = true;
        val.push_back(x);
        used[x] = true;
        val.push_back(x + 1);
        used[x + 1] = true;
        val.push_back(x - 2);
        used[x - 2] = true;
    }

    if (val.empty()) {
        if (N == 2 && x == 2) {
            cout << "Yes\n";
            cout << "1\n";
            cout << "2\n";
            cout << "3\n";
        } else {
            cout << "No\n";
        }
    } else {
        int left = bottom / 2 - 1;
        for (int i = 1; i <= bottom; ++i) {
            if (!used[i]) {
                if (--left >= 0) val.push_front(i);
                else val.push_back(i);
            }
        }

        cout << "Yes\n";
        while (!val.empty()) {
            cout << val.front() << '\n';
            val.pop_front();
        }
    }
}

